const [error, setError] = useState<string | null>(null);
const load = useCallback(async () => {
  setLoading(true);
  setError(null);
  try {
    const result = await api.incidents({ ... });
    setData(result);
  } catch (err) {
    setError(err instanceof Error ? err.message : 'Failed to load incidents');
  } finally {
    setLoading(false);
  }
}, [...]);
